package com.example.ptchampion.ui.screens.camera\n\nimport android.Manifest\nimport android.content.Context\nimport android.util.Log\nimport androidx.camera.core.CameraSelector\nimport androidx.camera.core.ImageAnalysis\nimport androidx.camera.core.Preview\nimport androidx.camera.lifecycle.ProcessCameraProvider\nimport androidx.camera.view.PreviewView\nimport androidx.compose.foundation.layout.*\nimport androidx.compose.material3.Button\nimport androidx.compose.material3.CircularProgressIndicator\nimport androidx.compose.material3.MaterialTheme\nimport androidx.compose.material3.Scaffold\nimport androidx.compose.material3.Text\nimport androidx.compose.runtime.*\nimport androidx.compose.ui.Alignment\nimport androidx.compose.ui.Modifier\nimport androidx.compose.ui.platform.LocalContext\nimport androidx.compose.ui.platform.LocalLifecycleOwner\nimport androidx.compose.ui.viewinterop.AndroidView\nimport androidx.core.content.ContextCompat\nimport androidx.hilt.navigation.compose.hiltViewModel\nimport androidx.lifecycle.LifecycleOwner\nimport com.example.ptchampion.posedetection.PoseOverlay\nimport com.google.accompanist.permissions.ExperimentalPermissionsApi\nimport com.google.accompanist.permissions.isGranted\nimport com.google.accompanist.permissions.rememberPermissionState\nimport com.google.accompanist.permissions.shouldShowRationale\nimport java.util.concurrent.ExecutorService\nimport java.util.concurrent.Executors\n\n@OptIn(ExperimentalPermissionsApi::class)\n@Composable\nfun CameraScreen(\n    exerciseType: String?, // Received from navigation args\n    viewModel: CameraViewModel = hiltViewModel()\n    // Add navigateBack callback if needed\n) {\n    val context = LocalContext.current\n    val lifecycleOwner = LocalLifecycleOwner.current\n    val permissionState = rememberPermissionState(permission = Manifest.permission.CAMERA)\n    val uiState by viewModel.uiState.collectAsState()\n\n    // Request permission explicitly when state requires it\n    LaunchedEffect(permissionState, uiState.permissionState) {\n        if (!uiState.permissionState.hasPermission && !uiState.permissionState.shouldShowRationale) {\n             Log.d(\"CameraScreen\", \"Requesting camera permission...\")\n             permissionState.launchPermissionRequest()\n        }\n    }\n\n    // Update ViewModel when permission status changes\n    LaunchedEffect(permissionState.status) {\n        Log.d(\"CameraScreen\", \"Permission status changed: ${permissionState.status}\")\n        viewModel.onPermissionResult(\n            granted = permissionState.status.isGranted,\n            shouldShowRationale = permissionState.status.shouldShowRationale\n        )\n    }\n\n    // Create and manage the camera executor service\n    val cameraExecutor = remember { Executors.newSingleThreadExecutor() }\n    DisposableEffect(Unit) {\n        onDispose { cameraExecutor.shutdown() }\n    }\n\n    Scaffold {\ paddingValues ->\n        Box(\n            modifier = Modifier\n                .fillMaxSize()\n                .padding(paddingValues),\n            contentAlignment = Alignment.Center\n        ) {\n            // Handle Initialization State\n            if (uiState.isInitializing) {\n                 Column(horizontalAlignment = Alignment.CenterHorizontally) {\n                    CircularProgressIndicator()\n                    Spacer(modifier = Modifier.height(8.dp))\n                    Text(\"Initializing Pose Detection...\")\n                }\n            } else if (uiState.initializationError != null) {\n                 Text(\"Error: ${uiState.initializationError}\", color = MaterialTheme.colorScheme.error)\n            } \n            // Handle Permission States\n            else if (!uiState.permissionState.hasPermission) {\n                Column(horizontalAlignment = Alignment.CenterHorizontally) {\n                    if (uiState.permissionState.shouldShowRationale) {\n                        Text(\"Camera permission is required to analyze exercises.\")\n                        Button(onClick = { permissionState.launchPermissionRequest() }) {\n                            Text(\"Grant Permission\")\n                        }\n                    } else {\n                        // Still waiting for grant or permanently denied\n                        Text(\"Please grant camera permission.\")\n                        // TODO: Handle permanent denial (e.g., link to settings)\n                    }\n                }\n            } \n            // Permissions granted and initialized -> Show Camera & Overlay\n            else {\n                // Use Box to layer CameraPreview and PoseOverlay\n                Box(modifier = Modifier.fillMaxSize()) {\n                    CameraPreview(\n                        context = context,\n                        lifecycleOwner = lifecycleOwner,\n                        cameraExecutor = cameraExecutor,\n                        modifier = Modifier.fillMaxSize(),\n                        onFrameAnalyzed = { imageProxy ->\n                            viewModel.processFrame(imageProxy)\n                        }\n                    )\n\n                    // Draw Overlay using results from ViewModel\n                    uiState.poseLandmarkerResult?.let {\ resultBundle ->\n                        PoseOverlay(\n                            resultBundle = resultBundle,\n                            modifier = Modifier.fillMaxSize()\n                        )\n                    }\n\n                    // Display Exercise Type and other UI (can be refined)\n                     Text(\n                         text = \"Exercise: ${exerciseType ?: \"Unknown\"}\",\n                         modifier = Modifier\n                             .align(Alignment.TopCenter)\n                             .padding(16.dp),\n                         style = MaterialTheme.typography.titleMedium,\n                         color = MaterialTheme.colorScheme.onBackground\n                     )\n\n                    // Display detection error if any\n                     uiState.detectionError?.let {\n                         Text(\n                             text = \"Detection Error: $it\",\n                             modifier = Modifier\n                                 .align(Alignment.BottomCenter)\n                                 .padding(16.dp),\n                             color = MaterialTheme.colorScheme.error\n                         )\n                     }\n                }\n            }\n        }\n    }\n}\n\n@Composable\nfun CameraPreview(\n    context: Context,\n    lifecycleOwner: LifecycleOwner,\n    cameraExecutor: ExecutorService,\n    modifier: Modifier = Modifier,\n    onFrameAnalyzed: (ImageProxy) -> Unit\n) {\n     AndroidView(\n         factory = { ctx ->\n             val previewView = PreviewView(ctx)\n             val cameraProviderFuture = ProcessCameraProvider.getInstance(ctx)\n\n             cameraProviderFuture.addListener({\n                 val cameraProvider = cameraProviderFuture.get()\n                 \n                 // Preview Use Case\n                 val preview = Preview.Builder().build().also {\n                     it.setSurfaceProvider(previewView.surfaceProvider)\n                 }\n\n                 // Image Analysis Use Case\n                 val imageAnalyzer = ImageAnalysis.Builder()\n                     // Configure analysis options if needed (e.g., resolution)\n                     // .setTargetResolution(Size(640, 480))\n                     .setBackpressureStrategy(ImageAnalysis.STRATEGY_KEEP_OLDEST)\n                     .build()\n                     .also {\n                         it.setAnalyzer(cameraExecutor) { imageProxy ->\n                             // Pass the frame for analysis\n                             onFrameAnalyzed(imageProxy)\n                             // IMPORTANT: ImageProxy must be closed manually here if not closed in ViewModel\n                             // However, our ViewModel closes it, so we don't close here.\n                         }\n                     }\n\n                 // Select Camera (prefer front camera for exercises)\n                 val cameraSelector = CameraSelector.Builder()\n                     .requireLensFacing(CameraSelector.LENS_FACING_FRONT)\n                     .build()\n\n                 try {\n                     // Unbind use cases before rebinding\n                     cameraProvider.unbindAll()\n\n                     // Bind use cases to camera\n                     cameraProvider.bindToLifecycle(\n                         lifecycleOwner,\n                         cameraSelector,\n                         preview,\n                         imageAnalyzer // Add the analyzer use case\n                     )\n                     Log.d(\"CameraPreview\", \"Camera Use Cases Bound\")\n                 } catch (exc: Exception) {\n                     Log.e(\"CameraPreview\", \"Use case binding failed\", exc)\n                 }\n\n             }, ContextCompat.getMainExecutor(ctx))\n             previewView\n         },\n         modifier = modifier\n     )\n} 